function admin_redirect($m){header('Location: review_center.php?message='.$m);exit;}
function admin_location_candidate(array $row, $source_provider = null, $source_place_id = null) {
 return [
  'name'=>$row['name']??$row['suggested_name']??'',
  'address'=>$row['street_address']??'',
  'phone'=>$row['phone']??'',
  'website'=>$row['website']??'',
  'latitude'=>$row['latitude']??null,
  'longitude'=>$row['longitude']??null,
  'source_provider'=>$source_provider??($row['source_provider']??null),
  'source_place_id'=>$source_place_id??($row['source_place_id']??null),
  'exclude_location_id'=>$row['id']??0,
 ];
}
function admin_duplicate_summary_for_candidate($conn, array $candidate){return craftcrawl_location_duplicate_summary(craftcrawl_location_duplicate_candidates($conn,$candidate));}
function admin_has_soft_duplicate(array $summary){return !empty($summary['soft_block']);}
function admin_has_hard_duplicate(array $summary){return !empty($summary['hard_block']);}
function admin_render_duplicate_summary(array $summary){
 if(empty($summary['hard_block'])&&empty($summary['soft_block'])&&empty($summary['warning']))return;
 echo '<div class="admin-duplicate-summary">';
 foreach(['hard_block'=>'Hard block','soft_block'=>'Needs confirmation','warning'=>'Warning'] as $confidence=>$label){
  if(empty($summary[$confidence]))continue;
  echo '<p class="admin-duplicate-'.$confidence.'"><strong>'.craftcrawl_admin_escape($label).':</strong> ';
  $bits=[]; foreach($summary[$confidence] as $m){$bits[]='#'.$m['id'].' '.$m['name'].' ('.str_replace('_',' ',$m['match_type']).')';}
  echo craftcrawl_admin_escape(implode('; ',$bits)).'</p>';
 }
 echo '</div>';
}
function admin_render_json_signal_list($value, $label){
 $signals=json_decode((string)$value,true);
 if(!is_array($signals)||empty($signals))return;
 echo '<p><strong>'.craftcrawl_admin_escape($label).':</strong> '.craftcrawl_admin_escape(implode('; ',$signals)).'</p>';
}
function admin_external_url($value){
 $value=trim((string)$value);
 if($value==='')return '';
 return preg_match('/^https?:\/\//i',$value)?$value:'https://'.$value;
}
function admin_google_maps_url(array $row){
 $raw=json_decode((string)($row['raw_place_json']??''),true);
 if(is_array($raw)&&!empty($raw['googleMapsUri']))return $raw['googleMapsUri'];
 if(!empty($row['source_place_id'])&&($row['source_provider']??'')==='google'){
  $query=trim((string)($row['name']??''));
  if($query==='')$query=trim(($row['latitude']??'').','.($row['longitude']??''));
  return 'https://www.google.com/maps/search/?api=1&query='.rawurlencode($query).'&query_place_id='.rawurlencode($row['source_place_id']);
 }
 if(!empty($row['latitude'])&&!empty($row['longitude']))return 'https://www.google.com/maps/search/?api=1&query='.rawurlencode($row['latitude'].','.$row['longitude']);
 return '';
}
function admin_bind_dynamic_params($stmt, $types, array &$params){
 if($types==='')return;
 $refs=[$types];
 foreach($params as $key=>&$value){$refs[]=&$value;}
 call_user_func_array([$stmt,'bind_param'],$refs);
}
