$import_sql="SELECT l.*,gpi.fit_score,gpi.suggested_category,gpi.google_primary_type,gpi.google_types,gpi.raw_place_json,gpi.positive_signals,gpi.negative_signals,gpi.decision_reason,gpi.search_term,gpi.decision,EXISTS(SELECT 1 FROM location_hours lh WHERE lh.location_id=l.id LIMIT 1) AS has_import_hours FROM locations l LEFT JOIN google_place_imports gpi ON gpi.location_id=l.id WHERE ".implode(' AND ',$import_where)." ORDER BY l.createdAt LIMIT ? OFFSET ?";
$import_query_params=$import_params;$import_query_params[]=$import_per_page;$import_query_params[]=$import_offset;$import_query_types=$import_types.'ii';$import_stmt=$conn->prepare($import_sql);admin_bind_dynamic_params($import_stmt,$import_query_types,$import_query_params);$import_stmt->execute();$imports=$import_stmt->get_result();
$readiness=$conn->query("SELECT l.*, ls.user_notes AS suggestion_user_notes FROM locations l LEFT JOIN location_suggestions ls ON ls.created_location_id=l.id WHERE l.visibility_status IN ('public_unclaimed','public_claimed') AND l.disabledAt IS NULL AND l.checkin_verification_enabled=FALSE AND NOT EXISTS (SELECT 1 FROM location_hours lh WHERE lh.location_id=l.id AND (lh.verifiedAt IS NOT NULL OR lh.source='business_owner')) ORDER BY l.name");
$disabled_locations=$conn->query("SELECT l.*,COUNT(DISTINCT blm.id) AS manager_count FROM locations l LEFT JOIN business_location_managers blm ON blm.location_id=l.id AND blm.relationship_status='approved' AND blm.disabledAt IS NULL WHERE l.disabledAt IS NOT NULL GROUP BY l.id ORDER BY l.disabledAt DESC,l.name");
$rejected_hidden=$conn->query("SELECT 'location' AS recovery_type,l.id AS location_id,NULL AS suggestion_id,l.name,l.location_type,l.visibility_status AS review_status,l.street_address,l.apt_suite,l.city,l.state,l.zip,l.adminNotes,l.createdAt,NULL AS user_notes,NULL AS mapbox_place_id,NULL AS suggested_by,NULL AS matched_location_id FROM locations l WHERE l.disabledAt IS NULL AND l.visibility_status IN ('rejected','hidden') UNION ALL SELECT 'suggestion' AS recovery_type,NULL AS location_id,ls.id AS suggestion_id,ls.suggested_name AS name,ls.suggested_type AS location_type,ls.status AS review_status,ls.street_address,ls.apt_suite,ls.city,ls.state,ls.zip,ls.adminNotes,COALESCE(ls.reviewedAt,ls.createdAt) AS createdAt,ls.user_notes,ls.mapbox_place_id,CONCAT(u.fName,' ',u.lName) AS suggested_by,ls.matched_location_id FROM location_suggestions ls INNER JOIN users u ON u.id=ls.suggested_by_user_id WHERE ls.status IN ('rejected','duplicate') ORDER BY createdAt DESC");
?>
